1	import type { IssueId, IssueStatus } from "./issue";
2	
3	/**
4	 * A single entry in the index file ‚Äî summary of an issue for fast lookup.
5	 */
6	export interface IndexEntry {
7	  id: IssueId;
8	  title: string;
9	  path: string;             // relative path to issue file
10	  status: IssueStatus;
11	  assignee: string | null;
12	  parentId: IssueId | null;
13	  tags: string[];
14	  priority: 1 | 2 | 3 | 4 | 5;
15	}
16	
17	/**
18	 * Index file structure ‚Äî two sorted arrays and a children map.
19	 *
20	 * Invariants:
21	 * - Both arrays are sorted by issue id (time-sortable).
22	 * - `open` contains entries where status !== "closed".
23	 * - `closed` contains entries where status === "closed".
24	 * - `childrenOf` keys only exist for issues that have children.
25	 */
26	export interface IndexFile {
27	  open: IndexEntry[];
28	  closed: IndexEntry[];
29	  childrenOf: Record<IssueId, IssueId[]>;
30	}
