1	import type { IssueId, CommentId, IssueProperties } from "./issue";
2	
3	/**
4	 * Base shape for all events.
5	 */
6	export interface BaseEvent {
7	  timestamp: string; // ISO 8601
8	  author: string;    // resolved user name or "system"
9	}
10	
11	/**
12	 * Creation event ‚Äî marks the birth of an issue. No content.
13	 */
14	export interface CreationEvent extends BaseEvent {
15	  type: "creation";
16	}
17	
18	/**
19	 * Update event ‚Äî records changes to issue properties.
20	 */
21	export interface UpdateEvent extends BaseEvent {
22	  type: "update";
23	  content: Partial<Pick<IssueProperties, "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId">> & {
24	    reason?: string; // for system auto-promotion events
25	  };
26	}
27	
28	/**
29	 * Comment event ‚Äî adds a new comment.
30	 */
31	export interface CommentEvent extends BaseEvent {
32	  type: "comment";
33	  content: {
34	    id: CommentId;
35	    content: string;
36	  };
37	}
38	
39	/**
40	 * Comment update event ‚Äî edits an existing comment.
41	 */
42	export interface CommentUpdateEvent extends BaseEvent {
43	  type: "comment-update";
44	  content: {
45	    id: CommentId;
46	    content: string;
47	  };
48	}
49	
50	/**
51	 * Comment delete event ‚Äî soft-deletes a comment.
52	 */
53	export interface CommentDeleteEvent extends BaseEvent {
54	  type: "comment-delete";
55	  content: {
56	    id: CommentId;
57	  };
58	}
59	
60	/**
61	 * Blockage added event ‚Äî records a new dependency.
62	 */
63	export interface BlockageAddedEvent extends BaseEvent {
64	  type: "blockage-added";
65	  content: {
66	    blockerId: IssueId;
67	  };
68	}
69	
70	/**
71	 * Blockage resolved event ‚Äî records dependency resolution.
72	 */
73	export interface BlockageResolvedEvent extends BaseEvent {
74	  type: "blockage-resolved";
75	  content: {
76	    blockerId: IssueId;
77	  };
78	}
79	
80	/**
81	 * Blockage deleted event ‚Äî records dependency removal.
82	 */
83	export interface BlockageDeletedEvent extends BaseEvent {
84	  type: "blockage-deleted";
85	  content: {
86	    blockerId: IssueId;
87	  };
88	}
89	
90	/**
91	 * Union of all event types.
92	 */
93	export type Event =
94	  | CreationEvent
95	  | UpdateEvent
96	  | CommentEvent
97	  | CommentUpdateEvent
98	  | CommentDeleteEvent
99	  | BlockageAddedEvent
100	  | BlockageResolvedEvent
101	  | BlockageDeletedEvent;
