1	/**
2	 * Issue ID ‚Äî 10 chars: 6 from timestamp base36 + 4 random base36
3	 * Sortable by creation time.
4	 */
5	export type IssueId = string;
6	
7	/**
8	 * Comment ID ‚Äî same format as IssueId: 10-char base36
9	 */
10	export type CommentId = string;
11	
12	/**
13	 * Issue status progression: idea ‚Üí todo ‚Üí in-progress ‚Üí done ‚Üí closed
14	 */
15	export type IssueStatus = "idea" | "todo" | "in-progress" | "done" | "closed";
16	
17	/**
18	 * Mutable properties of an issue, reconstructed by replaying events.
19	 */
20	export interface IssueProperties {
21	  id: IssueId;
22	  title: string;
23	  description: string;
24	  status: IssueStatus;
25	  assignee: string | null;
26	  parentId: IssueId | null;
27	  tags: string[];
28	  priority: 1 | 2 | 3 | 4 | 5;
29	}
30	
31	/**
32	 * Full computed state of an issue, including computed fields.
33	 */
34	export interface ComputedIssue extends IssueProperties {
35	  createdAt: string;   // ISO 8601 ‚Äî timestamp of creation event
36	  createdBy: string;   // author of creation event
37	  updatedAt: string;   // ISO 8601 ‚Äî timestamp of last event
38	}
39	
