42	/**
43	 * Tracker ‚Äî the main programmatic API for trackgentic.
44	 *
45	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
46	 * It does NOT validate that `.trackgentic/` exists ‚Äî resolution happens on each method call.
47	 */
48	export class Tracker {
49	  private cwd: string;
50	
51	  constructor(cwd?: string) {
52	    this.cwd = cwd ?? process.cwd();
53	  }
54	
55	  /**
56	   * Initialize a new `.trackgentic/` directory in `cwd`.
57	   *
58	   * Creates the directory with:
59	   * - config.json ‚Äî default auth config
60	   * - index.json ‚Äî empty open/closed arrays, empty childrenOf map
61	   * - dependencies.json ‚Äî empty blockedBy/blocks maps
62	   * - users.json ‚Äî empty users array
63	   * - issues/ ‚Äî empty directory
64	   *
65	   * Idempotent: if `.trackgentic/` already exists, returns ALREADY_INITIALIZED
66	   * without overwriting any files.
67	   */
68	  async init(): Promise<InitResult> {
69	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
70	
71	    if (existsSync(trackerDir)) {
72	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
73	    }
74	
75	    // Create the main directory
76	    mkdirSync(trackerDir, { recursive: true });
77	
78	    // Create issues subdirectory
79	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
80	
81	    // Write initial files
82	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
83	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
84	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
85	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
86	
87	    return { result: "OK", path: resolve(trackerDir) };
88	  }
89	}
